render_animals_section() {
  local id="$1"
  local image_file="$2"
  local f="$DATA/$id.animals.json"
  if [ ! -f "$f" ]; then
    cat <<EOF
<div class="section-block">
  <div class="section-head"><span class="icon animals">⌒</span><span class="label">Animals (cat/dog)</span><span class="stats">no result</span></div>
