    lab=$(echo "$row"  | jq -r '.label')
    conf=$(echo "$row" | jq -r '.confidence')
    x=$(echo "$row"  | jq -r '.x'); y=$(echo "$row" | jq -r '.y')
    w=$(echo "$row"  | jq -r '.width'); h=$(echo "$row" | jq -r '.height')
    thumb=$(bbox_thumb "$image_file" "$IMG_W" "$IMG_H" "$x" "$y" "$w" "$h")
