}

# Per-card JSON file links. Lists every capability JSON for the item.
# Each link points to a file under site/data/ that contains the full,
# un-truncated auge output for that capability.
json_link_list() {
  local id="$1"
  local f label size
  for f in "$DATA/$id".*.json "$DATA/$id.json"; do
    [ -f "$f" ] || continue
    label=$(basename "$f")
    # capability portion: between $id. and .json (or "all" if just $id.json)
    case "$label" in
      "$id.json")          cap="all" ;;
      "$id".*.json)
        cap="${label#$id.}"
        cap="${cap%.json}"
        ;;
      *)                    continue ;;
    esac
    size=$(awk -v b="$(stat -f%z "$f" 2>/dev/null || stat -c%s "$f")" 'BEGIN{
      if (b<1024) printf "%d B", b;
      else if (b<1048576) printf "%.1f KB", b/1024;
      else printf "%.1f MB", b/1048576
    }')
    printf '        <li><a href="data/%s" target="_blank" rel="noopener"><code>--%s</code> <span class="size">%s</span></a></li>\n' \
      "$label" "$cap" "$size"
  done
}

render_face_overlay() {
  local json_file="$1"
  local items_json
  items_json=$(jq -c '.results.faces.faces // .results.faces // []' "$json_file" 2>/dev/null || echo '[]')
  local count
  count=$(echo "$items_json" | jq 'length')
  if [ "$count" -eq 0 ]; then return; fi
  echo '<div class="face-overlay">'
  local i=0
  echo "$items_json" | jq -c '.[]' | while IFS= read -r row; do
    i=$((i+1))
    local x y w h left top width height
    x=$(echo "$row" | jq -r '.x'); y=$(echo "$row" | jq -r '.y')
    w=$(echo "$row" | jq -r '.width'); h=$(echo "$row" | jq -r '.height')
    left=$(awk "BEGIN { printf \"%.2f\", $x * 100 }")
    top=$(awk "BEGIN { printf \"%.2f\", (1 - $y - $h) * 100 }")
    width=$(awk "BEGIN { printf \"%.2f\", $w * 100 }")
    height=$(awk "BEGIN { printf \"%.2f\", $h * 100 }")
    printf '<div class="face-box" style="left:%s%%;top:%s%%;width:%s%%;height:%s%%"><div class="label">face %d</div></div>\n' \
      "$left" "$top" "$width" "$height" "$i"
  done
  echo '</div>'
}

build_card() {
  local idx="$1"
  local id title year category license source_url filename blurb args_json
  id=$(jq -r ".items[$idx].id" "$MANIFEST")
  title=$(jq -r ".items[$idx].title" "$MANIFEST")
  year=$(jq -r ".items[$idx].year" "$MANIFEST")
  category=$(jq -r ".items[$idx].category" "$MANIFEST")
  license=$(jq -r ".items[$idx].license" "$MANIFEST")
  source_url=$(jq -r ".items[$idx].source" "$MANIFEST")
  filename=$(jq -r ".items[$idx].filename" "$MANIFEST")
  blurb=$(jq -r ".items[$idx].blurb" "$MANIFEST")
  args_json=$(jq -c ".items[$idx].auge_args" "$MANIFEST")

  local src_image="$SOURCE/$filename"
  if [ ! -f "$src_image" ]; then return; fi

  local display_filename="$filename"
  if [[ "$filename" == *.pdf ]] || [[ "$filename" == *.PDF ]]; then
    local png_thumb="${filename%.*}.png"
    local png_path="$IMAGES/$png_thumb"
    if [ ! -f "$png_path" ]; then
      sips -s format png "$src_image" --out "$png_path" >/dev/null 2>&1 || cp "$src_image" "$png_path"
      sips -Z 900 "$png_path" --out "$png_path" >/dev/null 2>&1 || true
    fi
    display_filename="$png_thumb"
  else
    sips -Z 900 "$src_image" --out "$IMAGES/$filename" >/dev/null 2>&1 || cp "$src_image" "$IMAGES/$filename"
  fi

  local json_file="$DATA/$id.json"
  local cmdline pretty title_e blurb_e license_e source_e IMG_W IMG_H
  cmdline=$(render_cmdline "$args_json" "$filename")
  title_e=$(echo "$title" | html_escape)
  blurb_e=$(echo "$blurb" | html_escape)
  license_e=$(echo "$license" | html_escape)
  source_e=$(echo "$source_url" | html_escape)

  # Source image natural dimensions — needed to make every bbox thumbnail
  # render with its REAL pixel-aspect ratio (not a forced square).
  IMG_W=$(sips -g pixelWidth  "$IMAGES/$display_filename" 2>/dev/null | awk '/pixelWidth/{print $2}')
  IMG_H=$(sips -g pixelHeight "$IMAGES/$display_filename" 2>/dev/null | awk '/pixelHeight/{print $2}')
  IMG_W=${IMG_W:-1000}
  IMG_H=${IMG_H:-1000}
  export IMG_W IMG_H   # subshells from $() inherit env

  cat <<EOF
<article class="card" id="$id">
  <div class="card-image">
    <div class="card-image-frame">
      <img src="images/$(echo "$display_filename" | html_escape)" alt="$title_e" loading="lazy" decoding="async" width="$IMG_W" height="$IMG_H">
$(render_horizon_overlay "$id")
$(render_contours_overlay "$id")
$(render_text_rectangles_overlay "$id")
$(render_subject_overlay "$id")
$(render_persons_mask_overlay "$id")
$(render_rectangles_overlay "$id")
$(render_saliency_overlay "$id")
$(render_animals_overlay "$id")
$(render_animal_pose_overlay "$id")
$(render_body_pose_overlay "$id")
$(render_hand_pose_overlay "$id")
$(render_landmarks_overlay "$id")
$(render_face_overlay "$json_file")
    </div>
  </div>
  <div class="card-body">
    <div class="card-meta">
      <span class="badge $category">$category</span>
      <span>$year</span>
      <span>$license_e</span>
    </div>
    <h3>$title_e</h3>
    <p class="blurb">$blurb_e</p>
    <code class="cmd-line">$cmdline</code>
$(render_ocr_section "$json_file")
$(render_classify_section "$json_file")
$(render_barcodes_section "$json_file")
$(render_faces_section "$json_file" "$display_filename")
$(render_face_landmarks_section "$id" "$display_filename")
$(render_animals_section "$id" "$display_filename")
$(render_animal_pose_section "$id" "$display_filename")
$(render_body_pose_section "$id" "$display_filename")
$(render_hand_pose_section "$id" "$display_filename")
$(render_aesthetics_section "$id")
$(render_smudge_section "$id")
$(render_saliency_section "$id" "attention" "saliency-attention" "$display_filename")
$(render_saliency_section "$id" "objectness" "saliency-objectness" "$display_filename")
$(render_rectangles_section "$id" "$display_filename")
$(render_text_rectangles_section "$id" "$display_filename")
$(render_horizon_section "$id" "$display_filename")
$(render_contours_section "$id" "$display_filename")
$(render_subject_section "$id" "$display_filename")
$(render_persons_mask_section "$id" "$display_filename")
$(render_feature_print_section "$id")
    <div class="section-block">
      <div class="section-head">
        <span class="icon json">{}</span>
        <span class="label">Raw JSON</span>
        <span class="stats">14 capability runs · on-device</span>
      </div>
      <div class="json-summary">
        Every Vision pass auge ran on this image. Click a file to see the full,
        un-truncated output (vector embeddings, full landmark points,
        every contour point — exactly what auge produced):
      </div>
      <ul class="json-links">
$(json_link_list "$id")
      </ul>
    </div>
    <a class="source-link" href="$source_e" target="_blank" rel="noopener">Wikimedia source</a>
  </div>
</article>
EOF
}

# ---- Compose ----
TMP_BODY=$(mktemp)
trap 'rm -f "$TMP_BODY"' EXIT

count=$(jq '.items | length' "$MANIFEST")
for i in $(seq 0 $((count - 1))); do
    id=$(jq -r ".items[$i].id" "$MANIFEST")
    printf "  %-40s built\n" "$id"
    build_card "$i" >> "$TMP_BODY"
done

# Generate the per-category table-of-contents linking to each card.
TMP_TOC=$(mktemp)
python3 - "$MANIFEST" > "$TMP_TOC" <<'PYEOF'
import json, sys, html
items = json.load(open(sys.argv[1]))['items']
CAT_LABEL = {
    'faces': 'Faces & people',
    'classify': 'Classification & objects',
    'barcode': 'Barcodes & QR',
    'multilingual': 'OCR & languages',
    'historical': 'Historical documents',
    'animals': 'Animals & wildlife',
}
ORDER = ['faces', 'classify', 'barcode', 'multilingual', 'historical', 'animals']
groups = {c: [] for c in ORDER}
for it in items:
    groups.setdefault(it.get('category', 'other'), []).append(it)
print('<nav class="corpus-toc" aria-label="Showcase examples">')
print('  <h3 class="corpus-toc-title">Jump to an example</h3>')
print('  <div class="corpus-toc-grid">')
for cat in ORDER:
    if not groups.get(cat): continue
    label = CAT_LABEL.get(cat, cat.title())
    print(f'    <div class="corpus-toc-group">')
    print(f'      <h4>{html.escape(label)} <span>({len(groups[cat])})</span></h4>')
    print('      <ul>')
    for it in groups[cat]:
        title = html.escape(it['title'])
        yr = it.get('year', '')
        yr_s = f' <span class="yr">{yr}</span>' if yr else ''
        print(f'        <li><a href="#{html.escape(it["id"])}">{title}</a>{yr_s}</li>')
    print('      </ul>')
    print('    </div>')
print('  </div>')
print('</nav>')
PYEOF
trap 'rm -f "$TMP_BODY" "$TMP_TOC"' EXIT

# Concatenate header + TOC + cards + footer, then substitute placeholders
{
  cat "$TPL/header.html"
  cat "$TMP_TOC"
  cat "$TMP_BODY"
  cat "$TPL/footer.html"
} | sed \
    -e "s|__VERSION__|$VERSION|g" \
    -e "s|__BUILD_ID__|$BUILD_ID|g" \
    -e "s|__TEST_COUNT__|$TEST_COUNT|g" \
    -e "s|__GENERATED__|$GENERATED|g" \
    -e "s|__CORPUS_TOTAL__|$CORPUS_TOTAL|g" \
    -e "s|__CORPUS_FACES__|$CORPUS_FACES|g" \
    -e "s|__CORPUS_OCR__|$CORPUS_OCR|g" \
    -e "s|__CORPUS_BARCODES__|$CORPUS_BARCODES|g" \
    -e "s|__CORPUS_CLASSIFY__|$CORPUS_CLASSIFY|g" \
    -e "s|__CORPUS_LANGS__|$LANG_COUNT|g" \
  > "$SITE/index.html"

echo ""
echo "auge-web: site built at $SITE/index.html"
ls -lh "$SITE/index.html"
